const API_BASE_URL = "http://localhost:8080/api";

/**
 * Calls the dummy login endpoint. Any non-empty username is accepted by the
 * backend - this just gives us a "logged in as X" identity plus a token to
 * stash in state.
 */
export async function login(username, password) {
  const response = await fetch(`${API_BASE_URL}/auth/login`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ username, password }),
  });

  if (!response.ok) {
    throw new Error("Login failed. Please try again.");
  }

  return response.json(); // { username, token }
}

/**
 * Fetches existing chat history once, so a newly-joined user sees prior
 * messages before the live WebSocket stream kicks in.
 */
export async function fetchMessageHistory() {
  const response = await fetch(`${API_BASE_URL}/messages`);

  if (!response.ok) {
    throw new Error("Failed to load message history.");
  }

  return response.json();
}
